+// ============================================================================
+// PlistValue - Union type for plist values
+// ============================================================================
+
+pub const PlistValue = union(enum) {
+    string: []const u8,
+    integer: i64,
+    real: f64,
+    boolean: bool,
+    data: []const u8,
+    date: i64, // Unix timestamp
